import React from 'react';
import { 
  Box, 
  Avatar, 
  Typography, 
  useTheme, 
  alpha,
  Tooltip,
  styled
} from '@mui/material';
import { motion } from 'framer-motion';
import { useFirebase } from '../../context/FirebaseContext';

// Styled components
const CompanyCircleContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(4),
  padding: theme.spacing(1),
  gap: theme.spacing(2),
  overflowX: 'auto',
  scrollbarWidth: 'none',
  '&::-webkit-scrollbar': {
    display: 'none'
  },
}));

const MainCompanyCircle = styled(motion.div)(({ theme }) => ({
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  cursor: 'pointer',
}));

const CompanyCircle = styled(motion.div)(({ theme }) => ({
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  cursor: 'pointer',
}));

const CompanyName = styled(Typography)(({ theme }) => ({
  marginTop: theme.spacing(1),
  fontWeight: 600,
  fontSize: '0.8rem',
  textAlign: 'center',
  maxWidth: 80,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
}));

interface CompanySelectorProps {
  // Optional props if needed
}

const CompanySelector: React.FC<CompanySelectorProps> = () => {
  const theme = useTheme();
  const { companies, activeCompany, setActiveCompany, loading } = useFirebase();

  if (loading || companies.length === 0) {
    return null;
  }

  // Separate main company from others
  const mainCompany = companies.find(company => company.isMain) || companies[0];
  const otherCompanies = companies.filter(company => company.id !== mainCompany.id);

  const handleCompanyClick = (company: typeof companies[0]) => {
    setActiveCompany(company);
  };

  return (
    <CompanyCircleContainer>
      {/* Main company - larger circle */}
      <MainCompanyCircle
        onClick={() => handleCompanyClick(mainCompany)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        <Avatar 
          src={mainCompany.logo} 
          alt={mainCompany.name}
          sx={{
            width: 80,
            height: 80,
            border: activeCompany?.id === mainCompany.id 
              ? `3px solid ${mainCompany.color}` 
              : `3px solid transparent`,
            boxShadow: activeCompany?.id === mainCompany.id 
              ? `0 0 10px ${alpha(mainCompany.color, 0.5)}` 
              : 'none',
            transition: 'all 0.3s ease',
            backgroundColor: alpha(mainCompany.color, 0.1),
          }}
        />
        <CompanyName variant="body2">
          {mainCompany.name}
        </CompanyName>
      </MainCompanyCircle>

      {/* Other companies - smaller circles */}
      {otherCompanies.map(company => (
        <Tooltip title={company.name} key={company.id}>
          <CompanyCircle
            onClick={() => handleCompanyClick(company)}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
          >
            <Avatar 
              src={company.logo} 
              alt={company.name}
              sx={{
                width: 50,
                height: 50,
                border: activeCompany?.id === company.id 
                  ? `2px solid ${company.color}` 
                  : `2px solid transparent`,
                boxShadow: activeCompany?.id === company.id 
                  ? `0 0 8px ${alpha(company.color, 0.5)}` 
                  : 'none',
                transition: 'all 0.3s ease',
                backgroundColor: alpha(company.color, 0.1),
              }}
            />
            <CompanyName variant="caption">
              {company.name}
            </CompanyName>
          </CompanyCircle>
        </Tooltip>
      ))}
    </CompanyCircleContainer>
  );
};

export default CompanySelector;
